public class ArrayStats {
    public static void main(String[] args) {
        // Example usage
        int[] array = {10, 20, 30, 40};
        Tuple stats = calculateArrayStats(array);
        System.out.println("Minimum: " + stats.get(0) + ", Maximum: " + stats.get(1) + ", Sum: " + stats.get(2) + ", Average: " + stats.get(3));
