    public static Tuple calculateArrayStats(int[] array) {
        if (array == null || array.length < 4) {
            throw new IllegalArgumentException("Array must have at least 4 elements");
        }

        int min = array[0];
        int max = array[0];
        int sum = 0;

        for (int num : array) {
            sum += num;
            if (num < min) min = num;
            if (num > max) max = num;
        }

        double average = (double) sum / array.length;

        return new Tuple(min, max, sum, average);
    }
}

class Tuple {
    private final int min;
    private final int max;
    private final int sum;
    private final double average;

    public Tuple(int min, int max, int sum, double average) {
        this.min = min;
        this.max = max;
        this.sum = sum;
        this.average = average;
    }

    public int get(int index) {
        switch (index) {
            case 0: return min;
            case 1: return max;
            case 2: return sum;
            case 3: return (int) average;
            default: throw new IllegalArgumentException("Invalid index");
        }
    }
}

