fn frequency_sort(s: &str) -> String {
    let mut freq: std::collections::HashMap<char, usize> = std::collections::HashMap::new();
    for c in s.chars() {
        *freq.entry(c).or_insert(0) += 1;
    }

    let mut sorted: Vec<(char, usize)> = freq.into_iter().collect();
    sorted.sort_by(|a, b| {
        // Sort by frequency descending, then by character ascending
        let freq_cmp = b.1.cmp(&a.1);
        if freq_cmp == std::cmp::Ordering::Equal {
            a.0.cmp(&b.0)
        } else {
            freq_cmp
        }
    });

    let mut result = String::new();
    for (c, _) in sorted {
        result.push(c);
    }

    result
}

