std::string normalizeURL(const std::string& url) {
    std::string result = url;

    // Check if URL has protocol
    size_t protocolPos = url.find("://");
    if (protocolPos != std::string::npos) {
        // Convert protocol to lowercase
        std::string protocol = url.substr(0, protocolPos);
        std::transform(protocol.begin(), protocol.end(), protocol.begin(), ::tolower);
        result = url.substr(protocolPos);
    } else {
        // Prepend 'http://' if no protocol
        result = "http://" + result;
    }

    // Split URL into parts
    size_t queryPos = result.find('?');
    size_t paramPos = result.find('&');

    std::vector<std::string> params;

    // Extract parameters
    if (queryPos != std::string::npos) {
        std::string query = result.substr(queryPos + 1);
        std::vector<std::string> paramList;
        std::string currentParam;

        while (queryPos != std::string::npos) {
            size_t paramEnd = queryPos;
            while (paramEnd < query.size() && query[paramEnd] != '&') {
                paramEnd++;
            }
            if (paramEnd > queryPos) {
                currentParam = query.substr(queryPos, paramEnd - queryPos);
                paramList.push_back(currentParam);
                queryPos = paramEnd + 1;
            } else {
                queryPos = query.size();
            }
        }

        // Sort parameters alphabetically by name
        std::sort(paramList.begin(), paramList.end());

        // Reconstruct URL with sorted parameters
        result = result.substr(0, queryPos) + "&" + std::accumulate(paramList.begin(), paramList.end(), std::string(""));
    }

    return result;
}

