    visited = [0] * n
    rec_stack = [False] * n
    has_cycle = False

    def dfs(u):
        if visited[u]:
            return
        if rec_stack[u]:
            nonlocal has_cycle
            has_cycle = True
            return
        rec_stack[u] = True
        visited[u] = 1
        for v in adj[u]:
            dfs(v)
        rec_stack[u] = False

    for u in range(n):
        if not visited[u]:
            dfs(u)

    return has_cycle
