std::string formatPath(const std::string& path) {
    // Normalize backslashes to forward slashes
    std::string normalizedPath = path;
    std::transform(normalizedPath.begin(), normalizedPath.end(), normalizedPath.begin(), 
                   [](unsigned char c) { return c == '\\' ? '/' : c; });

    // Remove consecutive slashes
    size_t pos = 0;
    while (pos < normalizedPath.size()) {
        if (normalizedPath[pos] == '/') {
            pos++;
            while (pos < normalizedPath.size() && normalizedPath[pos] == '/') {
                pos++;
            }
        } else {
            pos++;
        }
    }

    // Handle network paths (e.g., \\server\share)
    if (normalizedPath[0] == '\\' && normalizedPath[1] == '\\') {
        normalizedPath = normalizedPath.substr(2);
    }

    return normalizedPath;
}

