use std::collections::HashMap;

struct Graph {
    vertices: HashMap<u32, Vec<Edge>>,
    num_vertices: u32,
    num_edges: u32,
}

struct Edge {
    source: u32,
    target: u32,
    weight: u32,
}

impl Graph {
    fn new() -> Self {
        Graph {
            vertices: HashMap::new(),
            num_vertices: 0,
            num_edges: 0,
        }
    }

    fn add_edge(&mut self, source: u32, target: u32, weight: u32) {
        if !self.vertices.contains_key(&source) {
            self.vertices.insert(source, Vec::new());
        }
        if !self.vertices.contains_key(&target) {
            self.vertices.insert(target, Vec::new());
        }
        self.vertices.get_mut(&source).unwrap().push(Edge { source, target, weight });
        self.num_edges += 1;
    }

    fn graph_edge_prune(&mut self, threshold_weight: u32) {
        let mut new_edges = HashMap::new();
        let mut visited = HashMap::new();

        for (source, edges) in self.vertices.iter() {
            for edge in edges {
                if edge.weight >= threshold_weight {
                    if !visited.contains_key(&source) {
                        visited.insert(source, true);
                    }
                    if !visited.contains_key(&edge.target) {
                        visited.insert(edge.target, true);
                    }
                    new_edges.insert(source, Vec::new());
                    new_edges.get_mut(&source).unwrap().push(edge);
                }
            }
        }

        self.vertices = new_edges;
        self.num_edges = new_edges.len() * 2; // Each edge is stored twice
    }
}
